console.log(fullName.toUpperCase()); // SARA AHMED
console.log(fullName.toLowerCase()); // sara ahmed
console.log(fullName.includes("Sara")); // true`,descriptionAr:"\u0627\u0644\u0639\u0645\u0644\u064A\u0627\u062A \u0627\u0644\u0634\u0627\u0626\u0639\u0629 \u0639\u0644\u0649 \u0627\u0644\u0646\u0635\u0648\u0635",descriptionEn:"Common string operations"}],editorLinks:[{label:"Programiz JS Editor",url:"https://www.programiz.com/javascript/online-compiler/",language:"javascript"}],keyPointsAr:["\u0627\u0644\u0646\u0635 \u064A\u064F\u0643\u062A\u0628 \u0628\u064A\u0646 \u0639\u0644\u0627\u0645\u0627\u062A \u0627\u0642\u062A\u0628\u0627\u0633 \u0645\u0641\u0631\u062F\u0629 \u0623\u0648 \u0645\u0632\u062F\u0648\u062C\u0629 \u0623\u0648 \u062E\u0644\u0641\u064A\u0629","\u062F\u0645\u062C \u0627\u0644\u0646\u0635\u0648\u0635 \u0628\u0627\u0633\u062A\u062E\u062F\u0627\u0645 + \u0623\u0648 Template Literals",".length \u064A\u064F\u0639\u0637\u064A\u0643 \u0639\u062F\u062F \u0627\u0644\u0623\u062D\u0631\u0641 \u0641\u064A \u0627\u0644\u0646\u0635","\u0627\u0644\u0646\u0635\u0648\u0635 \u0641\u064A JavaScript \u063A\u064A\u0631 \u0642\u0627\u0628\u0644\u0629 \u0644\u0644\u062A\u063A\u064A\u064A\u0631 \u0645\u0628\u0627\u0634\u0631\u0629"],keyPointsEn:["Strings are written between single, double, or backtick quotes","Concatenate strings using + or Template Literals",".length gives you the number of characters in the string","Strings in JavaScript are immutable (you create new ones)"]},{id:9,part:2,partTitleAr:"\u0627\u0644\u0644\u0628\u0646\u0627\u062A \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0629",partTitleEn:"Core Building Blocks",titleAr:"\u0627\u0644\u0639\u0645\u0644\u064A\u0627\u062A \u0627\u0644\u062D\u0633\u0627\u0628\u064A\u0629 \u0648\u0627\u0644\u0645\u0646\u0637\u0642\u064A\u0629",titleEn:"Operators",descriptionAr:"\u062A\u0639\u0644\u0645 \u0627\u0644\u0645\u0639\u0627\u0645\u0644\u0627\u062A \u0627\u0644\u062D\u0633\u0627\u0628\u064A\u0629 \u0648\u0627\u0644\u0645\u0642\u0627\u0631\u0646\u0629 \u0648\u0627\u0644\u0645\u0646\u0637\u0642\u064A\u0629 \u0627\u0644\u062A\u064A \u062A\u064F\u0645\u0643\u0651\u0646\u0643 \u0645\u0646 \u0625\u062C\u0631\u0627\u0621 \u0627\u0644\u0639\u0645\u0644\u064A\u0627\u062A \u0641\u064A \u0628\u0631\u0627\u0645\u062C\u0643.",descriptionEn:"Learn arithmetic, comparison, and logical operators that let you perform operations in your programs.",estimatedTime:"30 min",level:"beginner",icon:"\u2795",color:"#3fb950",conceptsAr:["\u0627\u0644\u0639\u0645\u0644\u064A\u0627\u062A \u0627\u0644\u062D\u0633\u0627\u0628\u064A\u0629","\u0639\u0645\u0644\u064A\u0627\u062A \u0627\u0644\u0645\u0642\u0627\u0631\u0646\u0629","\u0627\u0644\u0639\u0645\u0644\u064A\u0627\u062A \u0627\u0644\u0645\u0646\u0637\u0642\u064A\u0629","\u0623\u0648\u0644\u0648\u064A\u0629 \u0627\u0644\u0639\u0645\u0644\u064A\u0627\u062A"],conceptsEn:["Arithmetic operators","Comparison operators","Logical operators","Operator precedence"],diagramType:"operators",codeExamples:[{language:"javascript",code:`// Arithmetic
let a = 10, b = 3;
console.log(a + b);  // 13
console.log(a - b);  // 7
console.log(a * b);  // 30
console.log(a / b);  // 3.333...
console.log(a % b);  // 1  (remainder)
console.log(a ** b); // 1000 (power)

// Comparison (returns boolean)
console.log(a > b);   // true
console.log(a === b); // false
console.log(a !== b); // true

// Logical
console.log(true && false); // false
console.log(true || false); // true
console.log(!true);         // false`,descriptionAr:"\u062C\u0645\u064A\u0639 \u0623\u0646\u0648\u0627\u0639 \u0627\u0644\u0645\u0639\u0627\u0645\u0644\u0627\u062A \u0641\u064A JavaScript",descriptionEn:"All types of operators in JavaScript"}],editorLinks:[{label:"Programiz JS Editor",url:"https://www.programiz.com/javascript/online-compiler/",language:"javascript"}],keyPointsAr:["% \u0647\u0648 \u0628\u0627\u0642\u064A \u0627\u0644\u0642\u0633\u0645\u0629 \u2014 \u0645\u0641\u064A\u062F \u062C\u062F\u064B\u0627 \u0641\u064A \u0627\u0644\u0628\u0631\u0645\u062C\u0629","=== \u064A\u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0642\u064A\u0645\u0629 \u0648\u0627\u0644\u0646\u0648\u0639 \u0645\u0639\u064B\u0627 (\u0623\u0641\u0636\u0644 \u0645\u0646 ==)",'&& \u064A\u0639\u0646\u064A "\u0648"\u060C || \u064A\u0639\u0646\u064A "\u0623\u0648"\u060C ! \u064A\u0639\u0646\u064A "\u0644\u064A\u0633"',"\u0627\u0644\u0639\u0645\u0644\u064A\u0627\u062A \u0627\u0644\u062D\u0633\u0627\u0628\u064A\u0629 \u0644\u0647\u0627 \u0623\u0648\u0644\u0648\u064A\u0629 \u0645\u062B\u0644 \u0627\u0644\u0631\u064A\u0627\u0636\u064A\u0627\u062A"],keyPointsEn:["% is the remainder \u2014 very useful in programming","=== checks value AND type (better than ==)",'&& means "and", || means "or", ! means "not"',"Arithmetic operators follow the same precedence as math"]},{id:10,part:2,partTitleAr:"\u0627\u0644\u0644\u0628\u0646\u0627\u062A \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0629",partTitleEn:"Core Building Blocks",titleAr:"\u062A\u062D\u0648\u064A\u0644 \u0627\u0644\u0623\u0646\u0648\u0627\u0639",titleEn:"Type Casting",descriptionAr:"\u062A\u0639\u0644\u0645 \u0643\u064A\u0641 \u062A\u062D\u0648\u0651\u0644 \u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A \u0645\u0646 \u0646\u0648\u0639 \u0625\u0644\u0649 \u0622\u062E\u0631 \u2014 \u0645\u0646 \u0631\u0642\u0645 \u0625\u0644\u0649 \u0646\u0635 \u0648\u0628\u0627\u0644\u0639\u0643\u0633.",descriptionEn:"Learn how to convert data from one type to another \u2014 from number to string and back.",estimatedTime:"20 min",level:"beginner",icon:"\u{1F504}",color:"#58a6ff",conceptsAr:["\u0627\u0644\u062A\u062D\u0648\u064A\u0644 \u0627\u0644\u0635\u0631\u064A\u062D","\u0627\u0644\u062A\u062D\u0648\u064A\u0644 \u0627\u0644\u0636\u0645\u0646\u064A","String()","Number()","parseInt() \u0648 parseFloat()"],conceptsEn:["Explicit conversion","Implicit conversion","String()","Number()","parseInt() and parseFloat()"],diagramType:"type-cast",codeExamples:[{language:"javascript",code:`// To Number
let str = "42";
let num = Number(str);
console.log(num, typeof num); // 42 "number"

let int = parseInt("3.7");
console.log(int); // 3

let float = parseFloat("3.7");
console.log(float); // 3.7

// To String
let age = 25;
let ageStr = String(age);
console.log(ageStr, typeof ageStr); // "25" "string"

// To Boolean
console.log(Boolean(0));   // false
