// Loop through array
for (let fruit of fruits) {
  console.log(fruit);
}`,descriptionAr:"\u0627\u0644\u0639\u0645\u0644\u064A\u0627\u062A \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0629 \u0639\u0644\u0649 \u0627\u0644\u0645\u0635\u0641\u0648\u0641\u0627\u062A",descriptionEn:"Basic array operations"}],editorLinks:[{label:"Programiz JS Editor",url:"https://www.programiz.com/javascript/online-compiler/",language:"javascript"}],keyPointsAr:["\u0627\u0644\u0645\u0635\u0641\u0648\u0641\u0629 \u062A\u0628\u062F\u0623 \u0628\u0627\u0644\u0641\u0647\u0631\u0633 0 \u0648\u0644\u064A\u0633 1","push() \u064A\u0636\u064A\u0641 \u0639\u0646\u0635\u0631\u064B\u0627 \u0641\u064A \u0627\u0644\u0646\u0647\u0627\u064A\u0629\u060C pop() \u064A\u062D\u0630\u0641 \u0645\u0646 \u0627\u0644\u0646\u0647\u0627\u064A\u0629",".length \u064A\u064F\u0639\u0637\u064A\u0643 \u0639\u062F\u062F \u0627\u0644\u0639\u0646\u0627\u0635\u0631 \u0641\u064A \u0627\u0644\u0645\u0635\u0641\u0648\u0641\u0629","\u064A\u0645\u0643\u0646\u0643 \u062A\u062E\u0632\u064A\u0646 \u0623\u0646\u0648\u0627\u0639 \u0645\u062E\u062A\u0644\u0641\u0629 \u0641\u064A \u0646\u0641\u0633 \u0627\u0644\u0645\u0635\u0641\u0648\u0641\u0629"],keyPointsEn:["Arrays are 0-indexed (first element is at index 0, not 1)","push() adds to the end, pop() removes from the end",".length gives you the number of elements","You can store different types in the same array"]},{id:14,part:3,partTitleAr:"\u0627\u062A\u062E\u0627\u0630 \u0627\u0644\u0642\u0631\u0627\u0631\u0627\u062A \u0648\u0627\u0644\u062A\u0643\u0631\u0627\u0631",partTitleEn:"Making Decisions & Repeating Work",titleAr:"\u0627\u0644\u062D\u0644\u0642\u0627\u062A \u0627\u0644\u062A\u0643\u0631\u0627\u0631\u064A\u0629",titleEn:"Loops",descriptionAr:"\u0627\u0644\u062D\u0644\u0642\u0627\u062A \u062A\u064F\u062A\u064A\u062D \u0644\u0643 \u062A\u0643\u0631\u0627\u0631 \u062A\u0646\u0641\u064A\u0630 \u0627\u0644\u0643\u0648\u062F \u0639\u062F\u0629 \u0645\u0631\u0627\u062A. \u062A\u0639\u0644\u0645 for \u0648while \u0648\u0643\u064A\u0641 \u062A\u062E\u062A\u0627\u0631 \u0627\u0644\u0645\u0646\u0627\u0633\u0628.",descriptionEn:"Loops let you repeat code multiple times. Learn for and while loops and how to choose the right one.",estimatedTime:"40 min",level:"beginner",icon:"\u{1F501}",color:"#3fb950",conceptsAr:["for loop","while loop","do...while","break \u0648 continue","\u0627\u0644\u062A\u0643\u0631\u0627\u0631 \u0639\u0644\u0649 \u0627\u0644\u0645\u0635\u0641\u0648\u0641\u0627\u062A"],conceptsEn:["for loop","while loop","do...while","break and continue","Iterating arrays"],diagramType:"loop-diagram",codeExamples:[{language:"javascript",code:`// for loop
for (let i = 1; i <= 5; i++) {
  console.log("Count: " + i);
}
// Count: 1
// Count: 2
// Count: 3
// Count: 4
// Count: 5`,descriptionAr:"\u062D\u0644\u0642\u0629 for \u2014 \u062A\u064F\u0639\u062F\u0651 \u0645\u0646 1 \u0625\u0644\u0649 5",descriptionEn:"for loop \u2014 counts from 1 to 5"},{language:"javascript",code:`// while loop
let count = 0;
while (count < 3) {
  console.log("Repeat #" + count);
  count++;
}

// break and continue
