// Step 1: Start with first element as largest
// Step 2: Compare with each element
// Step 3: Update if larger found

function findMax(numbers) {
  let max = numbers[0];
  for (let num of numbers) {
    if (num > max) {
      max = num;
    }
  }
  return max;
}

let nums = [3, 7, 2, 9, 1, 5];
console.log(findMax(nums)); // 9`,descriptionAr:"\u062D\u0644 \u0645\u0634\u0643\u0644\u0629 \u0625\u064A\u062C\u0627\u062F \u0623\u0643\u0628\u0631 \u0631\u0642\u0645 \u0641\u064A \u0645\u0635\u0641\u0648\u0641\u0629 \u062E\u0637\u0648\u0629 \u0628\u062E\u0637\u0648\u0629",descriptionEn:'Solving the "find max number" problem step by step'}],editorLinks:[{label:"Programiz JS Editor",url:"https://www.programiz.com/javascript/online-compiler/",language:"javascript"}],keyPointsAr:["\u0627\u0641\u0647\u0645 \u0627\u0644\u0645\u0634\u0643\u0644\u0629 \u0623\u0648\u0644\u064B\u0627 \u0642\u0628\u0644 \u0623\u0646 \u062A\u0643\u062A\u0628 \u0623\u064A \u0643\u0648\u062F","\u0642\u0633\u0651\u0645 \u0627\u0644\u0645\u0634\u0643\u0644\u0629 \u0627\u0644\u0643\u0628\u064A\u0631\u0629 \u0625\u0644\u0649 \u0645\u0634\u0643\u0644\u0627\u062A \u0635\u063A\u064A\u0631\u0629 \u0623\u0628\u0633\u0637","\u0627\u0643\u062A\u0628 Pseudocode (\u0643\u0648\u062F \u0648\u0647\u0645\u064A) \u0644\u062A\u0646\u0638\u064A\u0645 \u0623\u0641\u0643\u0627\u0631\u0643","\u0627\u062E\u062A\u0628\u0631 \u0627\u0644\u062D\u0644 \u0628\u062D\u0627\u0644\u0627\u062A \u0645\u062E\u062A\u0644\u0641\u0629 \u0645\u0646\u0647\u0627 \u062D\u0627\u0644\u0627\u062A \u0627\u0644\u062D\u0627\u0641\u0629"],keyPointsEn:["Understand the problem first before writing any code","Break large problems into smaller, simpler sub-problems","Write Pseudocode to organize your thoughts","Test your solution with different cases including edge cases"]},{id:19,part:6,partTitleAr:"\u062E\u0644\u0641 \u0627\u0644\u0643\u0648\u0627\u0644\u064A\u0633 (\u0627\u062E\u062A\u064A\u0627\u0631\u064A)",partTitleEn:"Under the Hood (Optional)",titleAr:"\u0627\u0644\u0628\u062A\u0627\u062A \u0648\u0627\u0644\u0628\u0627\u064A\u062A\u0627\u062A",titleEn:"Bits and Bytes",descriptionAr:"\u0627\u0643\u062A\u0634\u0641 \u0643\u064A\u0641 \u064A\u062E\u0632\u0646 \u0627\u0644\u062D\u0627\u0633\u0648\u0628 \u0643\u0644 \u0634\u064A\u0621 \u0643\u0623\u0631\u0642\u0627\u0645 \u062B\u0646\u0627\u0626\u064A\u0629 \u2014 \u0628\u062A\u0627\u062A \u0648\u0628\u0627\u064A\u062A\u0627\u062A.",descriptionEn:"Discover how computers store everything as binary numbers \u2014 bits and bytes.",estimatedTime:"30 min",level:"intermediate",icon:"\u{1F4BE}",color:"#f85149",conceptsAr:["\u0627\u0644\u0628\u062A (Bit)","\u0627\u0644\u0628\u0627\u064A\u062A (Byte)","\u0627\u0644\u0643\u064A\u0644\u0648\u0628\u0627\u064A\u062A \u0648\u0627\u0644\u0645\u064A\u062C\u0627\u0628\u0627\u064A\u062A","\u062A\u0645\u062B\u064A\u0644 \u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A"],conceptsEn:["Bit","Byte","Kilobyte and Megabyte","Data representation"],diagramType:"bits-bytes",codeExamples:[{language:"javascript",code:`// Convert number to binary
